+/*
+* class ModelTypeDatabase
+*/
+class ModelTypeDatabase
+{
+public:
+  struct Record
+  {
+    std::string type_name;
+    std::string file_name;
+    AgentPose3d pose;
+    std::string animation;
+    double animation_speed;
+  };
+
+  using RecordPtr = std::shared_ptr<Record>;
+
+  //Create a new record and returns a reference to the record
