+bool CrowdSimInterface::init_crowd_sim()
+{
+  _menge_handle = MengeHandle::init_and_make(
+    _resource_path,
+    _behavior_file,
+    _scene_file,
+    _sim_time_step);
+
+  if (!_sdf_loaded)
+  {
+    RCLCPP_ERROR(
+      logger(),
+      "Please load the sdf before initialize the crowd_sim interface!");
+    return false;
+  }
+  _spawn_object();
+  return true;
+}
